class Solution:
    def numFriendRequests(self, ages):
        """
        :type ages: List[int]
        :rtype: int
        """
        count = [0] * 121
        for age in ages:
            count[age] += 1

        requests = 0
        for age in range(1, 121):
            if count[age] == 0:
                continue

            # Can send to people with age > 0.5*age + 7 and age <= age
            min_age = age // 2 + 7

            if min_age < age:
                # Count people in valid range
                valid_count = sum(count[min_age+1:age+1]) - 1  # Exclude self
                requests += count[age] * valid_count

        return requests
